import java.util.PriorityQueue;
import java.util.Scanner;

public class Main {
    static final int N = 1000;
    static final int M = 1000000;
    static int n, m;
    static int[][] adj = new int[N][N];
    static boolean[] vis = new boolean[N];
    static int edge_count;
    static int[][] edges = new int[M][3];

    static class Edge implements Comparable<Edge> {
        int u, v, w;
        Edge(int u, int v, int w) {
            this.u = u;
            this.v = v;
            this.w = w;
        }
        @Override
        public int compareTo(Edge other) {
            return Integer.compare(w, other.w);
        }
    }

    static PriorityQueue<Edge> pq = new PriorityQueue<>();

    static void push_edge(int u, int v, int w) {
        pq.add(new Edge(u, v, w));
    }

    static void prims(int source) {
        int mst_weight = 0;
        vis[source] = true;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (adj[i][j] != 0 && !vis[j]) {
                    push_edge(i, j, adj[i][j]);
                }
            }
        }
        while (!pq.isEmpty()) {
            Edge edge = pq.poll();
            int u = edge.u;
            int v = edge.v;
            int w = edge.w;
            if (!vis[v]) {
                vis[v] = true;
                mst_weight += w;
                System.out.println(u + " " + v);
            }
        }
        System.out.println(mst_weight);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        m = sc.nextInt();
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 0; i < m; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            int w = sc.nextInt();
            adj[u][v] = w;
            adj[v][u] = w;
        }
        prims(1);
    }
}

